"use client";
import * as React from "react";
import { buttonAnatomy } from "@tessera/core";

export interface ButtonProps extends React.ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: "solid" | "outline" | "ghost" | "danger";
  size?: "sm" | "md" | "lg";
  /** Shows a spinner and disables interaction while preserving button width. */
  loading?: boolean;
}

export const Button = React.forwardRef<HTMLButtonElement, ButtonProps>(function Button(
  { variant = "solid", size = "md", loading = false, disabled, children, ...rest },
  ref
) {
  return (
    <button
      type="button"
      {...buttonAnatomy.attrs("root")}
      data-variant={variant}
      data-size={size}
      data-loading={loading || undefined}
      disabled={disabled || loading}
      aria-busy={loading || undefined}
      ref={ref}
      {...rest}
    >
      {loading && <span {...buttonAnatomy.attrs("spinner")} aria-hidden />}
      <span {...buttonAnatomy.attrs("label")}>{children}</span>
    </button>
  );
});

@layer tessera.recipes {
  [data-scope="button"][data-part="root"] {
    /* Component-tier tokens: override these to retheme buttons locally. */
    --button-bg: var(--ts-accent-default);
    --button-fg: var(--ts-fg-onAccent);
    --button-border: transparent;
    --button-bg-hover: var(--ts-accent-emphasis);

    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: var(--ts-space-2);
    border: 1px solid var(--button-border);
    border-radius: var(--ts-radius-md);
    background: var(--button-bg);
    color: var(--button-fg);
    font-size: var(--ts-font-size-sm);
    font-weight: var(--ts-font-weight-medium);
    line-height: 1;
    padding: 0 var(--ts-space-4);
    height: 2.25rem;
    cursor: pointer;
    user-select: none;
    text-decoration: none;
    white-space: nowrap;
    transition:
      background-color var(--ts-duration-fast) var(--ts-easing-standard),
      border-color var(--ts-duration-fast) var(--ts-easing-standard),
      color var(--ts-duration-fast) var(--ts-easing-standard);
  }

  [data-scope="button"][data-part="root"]:hover:not(:disabled):not([data-loading]) {
    background: var(--button-bg-hover);
  }

  [data-scope="button"][data-part="root"][data-size="sm"] {
    height: 1.875rem;
    padding: 0 var(--ts-space-3);
    font-size: var(--ts-font-size-xs);
  }

  [data-scope="button"][data-part="root"][data-size="lg"] {
    height: 2.75rem;
    padding: 0 var(--ts-space-6);
    font-size: var(--ts-font-size-md);
  }

  [data-scope="button"][data-part="root"][data-variant="outline"] {
    --button-bg: transparent;
    --button-fg: var(--ts-fg-default);
    --button-border: var(--ts-border-default);
    --button-bg-hover: var(--ts-bg-subtle);
  }

  [data-scope="button"][data-part="root"][data-variant="ghost"] {
    --button-bg: transparent;
    --button-fg: var(--ts-fg-default);
    --button-bg-hover: var(--ts-bg-subtle);
  }

  [data-scope="button"][data-part="root"][data-variant="danger"] {
    --button-bg: var(--ts-danger-default);
    --button-fg: var(--ts-fg-onAccent);
    --button-bg-hover: var(--ts-danger-emphasis);
  }

  [data-scope="button"][data-part="root"][data-loading] {
    cursor: progress;
  }

  [data-scope="button"][data-part="spinner"] {
    width: 1em;
    height: 1em;
    border-radius: var(--ts-radius-full);
    border: 2px solid currentColor;
    border-top-color: transparent;
    animation: tessera-spin 0.7s linear infinite;
  }

  @keyframes tessera-spin {
    to {
      transform: rotate(360deg);
    }
  }
}
